var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"메이드장님. 카메라 세팅 완료되었습니다.","JPN":"メイド長、カメラのセット完了しました。","ENG":"Chief Maid, the camera setup is complete.","TWN":"女僕長大人，相機設定完成了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"히히, 완벽한 작전임다! 주인님도 깜짝 놀라시겠지 말임다!","JPN":"ひひっ、完璧な作戦っす！　ご主人様も絶対びっくりするっすよ！","ENG":"Hehe. Mission success, ma'am! Master will be totally surprised!","TWN":"嘻嘻，這真是個完美作戰！主人一定會嚇一跳！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"자 그럼 모네부터 시작해 볼까요?","JPN":"さあ、ではモネから始めましょうか？","ENG":"Then let us begin with Mone, shall we.","TWN":"那麼就從莫妮開始吧？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"맡겨만 주시지 말임다!","JPN":"任せてくださいっす！","ENG":"Leave it to me, ma'am!","TWN":"包在我身上！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"짜잔! 깜짝 서프라이즈임다 주인님~!","JPN":"じゃじゃーん！　ビッグサプライズっす、ご主人様！","ENG":"Ta-da! Surprise, Master!","TWN":"鏘鏘！驚喜來了，主人～！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"오늘은 주인님의 생일을 맞아 선배님들과 함께 축하 영상을 찍기로 했슴다!","JPN":"今日はご主人様の誕生日ってことで、先輩たちと一緒にお祝いの映像を撮ることにしたっす！","ENG":"To celebrate your birthday, I teamed up with my seniors to film this special video, sir!","TWN":"今天為了慶祝主人生日，我們和前輩們一起拍了祝賀影片！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"각자 진심을 담아 멘트를 준비했지 말임다! 첫 타자는 바로 저 모네임다!","JPN":"みんな気持ちを込めたメッセージを準備したっす！　そして一番乗りはこのモネっす！","ENG":"Everyone prepared a heartfelt message. First up is me, Mone!","TWN":"大家都準備了自己的真心話！第一棒就是我莫妮！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그럼……!","JPN":"それじゃ……！","ENG":"Then...!","TWN":"那麼……！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"주인님 생일 축하함다! 제 생일보다 훨씬 더 기쁜 날이지 말임다!","JPN":"ご主人様、誕生日おめでとうっす！　モネの誕生日よりずっと嬉しい日っす！","ENG":"Happy birthday, Master! This day is way happier than my own birthday!","TWN":"主人生日快樂！這是比我自己的生日還要開心的一天！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"저희 엄니도 엄청 축하해 줬슴다! 선물로 코코넛 크림도 보내줬지 말임다!","JPN":"モネの母ちゃんもすごく祝ってくれたっす！　プレゼントにココナッツオイルも送ってくれたっす！","ENG":"Mama said happy birthday too! She even sent coconut cream as a gift, sir!","TWN":"我媽媽也超級替您開心！還送了椰子奶油當禮物！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"물론 저도 같이 선물을 준비했는데, 뭔지 궁금하지 않슴까?","JPN":"もちろん、プレゼントはモネも準備したっすけど、何だと思いますか？","ENG":"And of course, I brought a gift too! Wanna know what it is, sir?","TWN":"當然我也準備了禮物，您很好奇是什麼吧？"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"짜자잔~! 바로 제 고향에서 준비한 특제 해산물 세트지 말임다!","JPN":"じゃじゃーん！　モネの故郷から持ってきた、特製海鮮セットっす！","ENG":"Ta-da! It's a special seafood set from my hometown, sir!","TWN":"鏘鏘～！就是我家鄉特製的海鮮禮盒！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"헤헤, 어제 새벽에 바다낚시에 가길 잘했슴다! 운수 대통이었지 말임다!","JPN":"へへっ。昨日明け方に海釣りに行って正解だったっす！　爆釣だったんすよ！","ENG":"Hehe. I am glad I went fishing at dawn yesterday! My luck was insane!","TWN":"嘿嘿，我昨天凌晨去海釣真是去對了！運氣爆棚！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"상하기 전에 빨리 와서 드셔 보시는 검다! 해산물은 싱싱할 때가 최고지 말임다!","JPN":"鮮度が落ちる前に、早く来て食べるっす！　海鮮は鮮度が命っす！","ENG":"Come grab it before it spoils, sir! Seafood tastes the best when it's fresh!","TWN":"快趁新鮮來吃吧！海鮮就是要趁新鮮享用！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"앗, 아하하…… 그러고 보니 저 혼자만 너무 떠든 것 같슴다.","JPN":"あ、あはは……なんか、モネばっかり喋っちまったっすね。","ENG":"Ah, ahaha... I think I talked a little too much alone.","TWN":"啊、啊哈哈……我好像講太久了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"좋아. 다음은 내 차례였지? 그럼 시작할게.","JPN":"よし。次は私の番ね？　始めるわよ。","ENG":"All right. It's my turn next, right?","TWN":"好。接下來輪到我了吧？那我開始了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"오! 리코리스 선배의 축하 멘트! 기대되지 말임다!","JPN":"お！　リコリス先輩のお祝いメッセージ！　楽しみっす！","ENG":"Oh! Lycoris's message! I cannot wait to hear what she's going to say!","TWN":"喔！莉克麗絲前輩的祝賀詞！好期待！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"흐, 흥! 딱히 대단한 건 아니라구.","JPN":"ふ、ふん！　別に大した内容じゃないわ。","ENG":"H-hmph! Don't make a big deal out of it.","TWN":"哼、哼！也沒什麼了不起的。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"생일 축하해. 당신 생일은 나에게도 있어 의미 있는 날이야.","JPN":"誕生日おめでとう。あんたの誕生日は、私にとっても意味のある日よ。","ENG":"Happy birthday. Your birthday means something to me too.","TWN":"生日快樂。你的生日，對我來說也是別有意義的一天。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"리코리스 선배! 당신이 아니라 주인님이지 말임다!","JPN":"リコリス先輩！　あんたじゃなくてご主人様っす！","ENG":"Lycoris! It's Master, not \\"you\\"!","TWN":"莉克麗絲前輩！不能說你，是主人才對！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"……생일날에는 케이크가 필수잖아?","JPN":"……誕生日にケーキは欠かせないでしょ？","ENG":"...Birthdays obviously need cake, right?","TWN":"……生日怎麼能少了蛋糕？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"당신을 위해 특별히 준비했어. 바로 특제 마라 맛 케이크.","JPN":"あんたのために特別に用意したわ。特製麻辣味ケーキよ。","ENG":"So I made one just for you. A super spicy mala cake.","TWN":"我特別為你準備了特製麻辣口味蛋糕。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"에엑?! 그건 살인임다! 그걸 드셨다간 분명 저 먼 곳으로 가버리고 말검다!","JPN":"ええっ！？　それは殺人っす！　それを食べたら遠くに旅立ってしまうっす！","ENG":"Whaaat?! That's practically a war crime, ma'am! If Master eats that, he might end up on another plane of existence!","TWN":"咦咦？！那是殺人武器欸！吃了那個一定會直接升天！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"마, 말하는데 자꾸 정신 사납게 하지 마!","JPN":"ちょ、ちょっと静かにしてよ。気が散るじゃない！","ENG":"S-stop butting in! You're throwing me off!","TWN":"别、別在我說話的時候一直鬧我啦！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"어, 어쨌든 생일은 진심으로 축하해. 영상 다 보면 꼭 나한테 찾아와줘.","JPN":"と、とにかく、誕生日おめでとう。これを見たら必ず私のところに来てちょうだい。","ENG":"A-anyway, happy birthday. After you finish the video, come find me.","TWN":"總之真心祝你生日快樂，看完影片一定要來找我。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"케이크만 먹고 갈 거 아니잖아? 그거 말고도 준비해 놓은 게 있어.","JPN":"ケーキだけ食べさせて帰すわけないでしょ？　他に準備したものもあるから。","ENG":"You're not planning to eat the cake and bail, right? Because I prepared something else too.","TWN":"你不會吃完蛋糕就走吧？我還有準備其他東西。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"에에에?! 뭠까 뭠까? 뭘 준비한 겁니까?!","JPN":"えええっ！？　なんすかなんすか？　何を準備したんすか！？","ENG":"Huh?! What is it? What did you prepare?!","TWN":"欸欸欸？！是什麼是什麼？妳到底準備了什麼？！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"설마 저번에 땡땡이치고 사라졌을 때, 사실 주인님의 선물을 사러 가셨던 검까?!","JPN":"まさかこないだ仕事サボって消えた時に、実はご主人様のプレゼントを買いに行ってたんすか！？","ENG":"Don't tell me you disappeared that time because you were out buying Master's present, were you?!","TWN":"難道妳上次翹班搞失蹤，其實是去買主人的禮物了嗎？！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"너 진짜! 자꾸 그러면 오늘부터 네 반찬은 전부 고추요리로 바꿔버린다?","JPN":"あんたね！　いい加減にしないと、今日からあんたのおかずに全部唐辛子入れちゃうわよ？","ENG":"Why you little! Keep that up, and I am swapping all your side dishes to chili-only dishes starting today!","TWN":"妳這傢伙！再亂說，從今天開始妳的配菜全部換成辣椒料理怎麼樣?"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"으에에엑! 그건 사양이지 말임다!","JPN":"うえええっ！　それは勘弁してくださいっす！","ENG":"Waaah! Anything but that!","TWN":"嗚欸欸！我拒絕！"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};